create table dirkspzm32.isi_transport_log (
    sid              varchar2(2 char) not null enable,
    firma_nr         number(6, 0) not null enable,
    transp_log_id    number(*, 0) not null enable,
    transp_id        number(*, 0) not null enable,
    status           varchar2(1 char) not null enable,
    login_id         number(*, 0),
    status_ts        timestamp(6) not null enable,
    log_typ          varchar2(10 char),
    arbeitsplatz_id  number(*, 0),
    check_typ        varchar2(10 char),
    scan_data        varchar2(255 char),
    check_q_eti_typ  varchar2(10 char),
    check_passed     varchar2(1 char),
    transaction_id   varchar2(50 char),
    transport_gruppe number(*, 5),
    res_id           number(*, 0),
    parent_transp_id number(*, 0),
    lte_id           varchar2(20 char)
);

alter table dirkspzm32.isi_transport_log
    add constraint pk_isi_transport_log primary key ( transp_log_id )
        using index enable;


